sp_widget.client_script:
api.controller = function ($rootScope, $timeout) {
    const c = this;

    c.onHistoryToggle = function () {
        const tableTransactionId =
            c.data?.tableWidget?.data?.transactionId || null;

        // Defer to let the flyout and nested widget settle before requesting data.
        $timeout(() => {
            $rootScope.$broadcast("scmTable:refresh", {
                transactionId: tableTransactionId,
            });
        }, 0);
    };
};

sp_widget.css:
.scm-history-flyout-content {
    width: 50vw;
}

.scm-history-flyout sdx-menu-flyout-toggle,
.scm-history-flyout sdx-menu-flyout-toggle::before,
.scm-history-flyout sdx-menu-flyout-toggle::after {
    background: transparent !important;
    border: 0 !important;
    box-shadow: none !important;
}

sp_widget.script:
(function () {
    const transactionId = input?.transactionId || gs.generateGUID();
    data.transactionId = transactionId;

    const logger = new Logger({
        transactionId: transactionId,
        source: "scm-history.server.js",
        includeTimeStamp: true,
        includeUserInfo: true,
        includeSessionId: true,
    });

    try {
        data.tableWidget = $sp.getWidget("scm-table", {
            transactionId: transactionId,
            tableProviderScriptInclude: "HistoryList",
        });
    } catch (error) {
        logger.error({
            message: "Error initializing history table widget",
            error: error.message,
        });
        data.tableWidget = null;
    }
})();
